// Extract message data from WhatsApp webhook payload
const entry = $input.first().json.body.entry[0];
const changes = entry.changes[0].value;
const message = changes.messages[0];
const contact = changes.contacts[0];

return [{
  json: {
    sender_phone: message.from,
    sender_name: contact.profile.name,
    message_text: message.text.body,
    message_id: message.id,
    timestamp: message.timestamp,
    phone_number_id: changes.metadata.phone_number_id,
    display_phone: changes.metadata.display_phone_number,
    wamid: message.id
  }
}];

const claudeResult = $input.first().json;
const msgData = $('Extract Message Data').first().json;

// Check if Claude API failed
const hasError = claudeResult.error || !claudeResult.content;

let parsed;
if (hasError) {
  // FALLBACK: Claude is down or errored
  parsed = {
    category: 'altro',
    needs_human: true,
    priority: 'high',
    response_text: 'Grazie per il messaggio! Un operatore del team AffittaSardegna ti risponderà a breve.',
    summary: 'Claude API non disponibile — messaggio passato direttamente agli operatori'
  };
} else {
  // Normal path: parse Claude response
  const responseText = claudeResult.content[0].text;
  try {
    let clean = responseText.trim();
    if (clean.startsWith('```')) {
      clean = clean.split('\n', 2)[1] || clean.substring(3);
      clean = clean.replace(/```\s*$/, '');
    }
    parsed = JSON.parse(clean.trim());
  } catch (e) {
    // Claude responded but not valid JSON — treat as needing human
    parsed = {
      category: 'altro',
      needs_human: true,
      priority: 'normal',
      response_text: 'Grazie per il messaggio! Un operatore del team AffittaSardegna ti risponderà a breve.',
      summary: 'Risposta Claude non parsabile: ' + responseText.substring(0, 200)
    };
  }
}

return [{
  json: {
    ...msgData,
    bot_response: parsed.response_text || 'Grazie, ti ricontatteremo a breve.',
    category: parsed.category || 'altro',
    needs_human: parsed.needs_human !== undefined ? parsed.needs_human : true,
    priority: parsed.priority || 'normal',
    summary: parsed.summary || '',
    claude_failed: hasError
  }
}];
